head.script:
scwin.memJson = $c.data.getMemInfo();
scwin.vempNo = scwin.memJson.empNo; // мӮ¬мӣҗлІҲнҳё
scwin.vepId = scwin.memJson.epId; // лӢӨмқҙл үнҠё м•„мқҙл””
scwin.vEqHomeClsCd = scwin.memJson.eqHomeClsCd; //м •л№„мҶҢмҶҚкө¬л¶„мҪ”л“ң
scwin.currDate = WebSquare.date.getFormattedDate (new Date(), "yyyyMMdd");

scwin.userId = scwin.memJson.userId;

console.log(scwin.memJson);

scwin.onpageload = function() {
    const codeOptions = [ 
        { grpCd : "EQ017", compID : "lc_inClsCd" },
        { grpCd : "ZZ021", compID : "lc_apprvStsCd, gr_eq420:apprvStsCd" },
    ];
    $c.data.setCommonCode(codeOptions);
    ica_inDt.setValue(scwin.currDate);
};

// кіөнҶөмҪ”л“ңк°Җ м…ӢнҢ…мқҙ лҗҳкі  scwin.ondataload мқҙлІӨнҠёк°Җ нҳём¶ң
scwin.ondataload = function() { 
    lc_homeClsCd.setValue(scwin.vEqHomeClsCd);
    if( "" == scwin.vEqHomeClsCd ) {
       lc_homeClsCd.setSelectedIndex(0); 
    }

    dlt_commonCodeZZ021.insertJSON(dlt_commonCodeZZ021.getRowCount(), [{"cd":"06","cdNm":"лҜёмҠ№мқё"}]);

    scwin.f_RetrieveFixWrkPl(lc_homeClsCd.getValue());
    lc_inClsCd.setSelectedIndex(0);
    lc_homeClsCd.focus();
};

// UDC м…ӢнҢ…мқҙ мқҙнӣ„..
scwin.onUdcCompleted = function() {
    $c.gus.cfInitObjects([ed_clntCdCond, ed_clntNmCond]);
};

//-------------------------------------------------------------------------
// мЎ°нҡҢ мЎ°кұҙ м§Җмҡ°кё°
//-------------------------------------------------------------------------
// function f_FieldClear = function() { 
// 	cfInitObjects(tb_eq420, null);
// }

//-------------------------------------------------------------------------
// мЎ°нҡҢ
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
	// н•„мҲҳмһ…л Ҙн•ӯлӘ© мІҙнҒ¬	  
    let ret = await $c.gus.cfValidate([lc_homeClsCd, ica_inDt]);
    if (!ret) {
        return false;
    }
    dma_search.set("inToDt", ica_inDt.getValue())
    $c.sbm.execute(sbm_search);
};

//------------------------------------------------------------------------
// [мһ‘м—…мһҘ  мҪӨліҙ мЎ°нҡҢ] мҶҢмҶҚ кө¬л¶„м—җ л”°лҘё мһ‘м—…мһҘ лҰ¬мҠӨнҠё мҪӨліҙ ліҖкІҪ ( мЎ°нҡҢмЎ°кұҙ LuxCombo )
//------------------------------------------------------------------------
scwin.f_RetrieveFixWrkPl = function(homeClsCd) {
    // ds_fixWrkPl.DataID = "/cm.zz.RetrieveComboCMD.do?sysCd=PsCommonEBC&queryId=retriveWrkplList&param1="+homeClsCd;
    // ds_fixWrkPl.Reset();
	dma_combo.set("sysCd", "PsCommonEBC");
	dma_combo.set("queryId", "retriveWrkplList");
	dma_combo.set("param1", homeClsCd);
	$c.sbm.execute(sbm_searchCombo);

};

scwin.udc_clntCdCond_onblurCodeEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_clntCdCond.getValue(), ed_clntNmCond.getValue(),'T','T');
};

scwin.udc_clntCdCond_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_clntCdCond.getValue(), ed_clntNmCond.getValue(),'T','T');
};

scwin.udc_clntCdCond_callback = function(rtnList) {
    if (rtnList != null ) {
    	if (rtnList[0] != "N/A") {
    		ed_clntCdCond.setValue(rtnList[0]);
			ed_clntCdCond.options.hidVal = rtnList[0];
			ed_clntNmCond.setValue(rtnList[1]);
		}
    } else {
		ed_clntCdCond.setValue("");
		ed_clntCdCond.options.hidVal = "";
		ed_clntNmCond.setValue("");
    }
};

//-------------------------------------------------------------------------
// кіөнҶө Popup мІҳлҰ¬ : Gubun Code м—җ л”°лҘё кіөнҶө Popup мқ„ нҳём¶ңн•ңлӢӨ.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {
  	// м„ м–ёл¶Җ
	// var rtnList;  //кіөнҶөPOP-UP -> мҡ”мІӯнҷ”л©ҙ 
	switch (disGubun)
  	{
  		case 1:
			// кұ°лһҳмІҳ нҢқм—…			
  			// rtnList = cfCommonPopUp('retrieveFixClntList'	// XMLмғҒмқҳ SELECT ID
            await udc_clntCdCond.cfCommonPopUp(
                                     scwin.udc_clntCdCond_callback
  									,pCode					// нҷ”л©ҙм—җм„ңмқҳ ??? Code Elementмқҳ	Value
  									,pName					// нҷ”л©ҙм—җм„ңмқҳ ??? Name Elementмқҳ	Value
  									,pClose					// кІ°кіјк°Җ 1кұҙ мқјл•Ң  мӣҗлҸ„мҡ°лҘј	AutoClose м—¬л¶Җ	(T:Close,F:Opened)
  									,null					// кІҖмғү кІ°кіј	м»¬лҹјмқҳ ліҙм—¬мЈјлҠ”	к°ңмҲҳ (SELECTм Ҳмқҳ мҲңм„ң) MAX:10 - default (2)
  									,null					// TitleмҲңм„ң	
  									,null					// ліҙм—¬мЈјлҠ” к°Ғ м»¬лҹјл“Өмқҳ нҸӯ	
                                    ,"3,4,5,6,7,8,9,10"		// м»¬лҹјмӨ‘м—җм„ң мҲЁкё°лҠ”	м»¬лҹј м§Җм •		
  									,null					// SQLм Ҳмқҳ WHEREм Ҳм—җ	мӣҗн•ҳлҠ” мЎ°кұҙмқ„ м„ нғқн•Ё MAX:8к°ңк№Ңм§Җ к°ҖлҠҘ
  									,null					// POP-UPлӣ°мқ„л•Ң мӣҗлҸ„мҡ°мқҳ	мӮ¬мҡ©мһҗ м •мқҳ	нҸӯ
  									,null					// POP-UPлӣ°мқ„л•Ң мҡ°лҸ„мҡ°мқҳ	мӮ¬мҡ©мһҗ м •мқҳ	лҶ’мқҙ	
  									,null					// мңҲлҸ„мҡ° мң„м№ҳ YмўҢн‘ң	
  									,null					// мңҲлҸ„мҡ° мң„м№ҳ XмўҢн‘ң
  									,null					// мӨ‘ліөмІҙнҒ¬м—¬л¶Җ	("F")
  									,pAllSearch				// м „мІҙкІҖмғүн—Ҳмҡ©м—¬л¶Җ	("F")
  									,"кұ°лһҳмІҳ,кұ°лһҳмІҳмҪ”л“ң,кұ°лһҳмІҳлӘ…"				// POP-UP Window Title кІҖмғүм–ҙ1,2	 ("WinнғҖмқҙнӢҖ,мІ«лІҲкІҖмғүNm,л‘җлІҲ?кІҖмғүNm")
  									);
			break;
	}
};

//-------------------------------------------------------------------------
// нҢқм—… мІҳлҰ¬мӢң кІҖмғүлҗң лҚ°мқҙн„°мқё кІҪмҡ° нҢқм—… мІҳлҰ¬ м•Ҳн•Ё.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    // к°’мқҙ мһ…л Ҙмқҙ м•Ҳлҗң кІҪмҡ°, н•ҙлӢ№ Text Boxк°Җ readonly мқё кІҪмҡ°, мқҙм „к°’кіј лҸҷмқјн•ң кІҪмҡ° нҢқм—…мқ„ мӢӨн–үн•ҳм§Җ м•ҠмқҢ.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // м§қмқҙ лҗҳлҠ” мҳӨлёҢм қнҠёмқҳ к°’ м ңкұ°
    $c.gus.cfClearPairObj(pairObj);

    // кІҖмғүм–ҙ м„ёнҢ…
    let pVal = $c.gus.cfGetValue(inObj);

    // inObjк°Җ мҪ”л“ң н•„л“ңмқј кІҪмҡ° нҢқм—…
    if (isCode === null || isCode === true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    }
    // inObjк°Җ мҪ”л“ңлӘ… н•„л“ңмқј кІҪмҡ° нҢқм—…
    else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

//------------------------------------------------------------------------
// лҰ¬нҸ¬нҠё м¶ңл Ҙ лІ„нҠј
//------------------------------------------------------------------------  
///var PGM_ID ="eq_520_01_13b.jsp";
scwin.f_OzReport = async function () {
	// н•„мҲҳмһ…л Ҙн•ӯлӘ© мІҙнҒ¬	  
    let ret = await $c.gus.cfValidate([lc_homeClsCd, ica_inDt]);
    if (!ret) {
        return false;
    }
    var data = {
        reportName: "/ps/eq/adjmmgnt/matprscond/eq_520_01_13.ozr",
        odiParam : {
                     homeClsCd: lc_homeClsCd.getValue()
                    ,homeClsNm: lc_homeClsCd.getText(true)
                    ,wrkPlCd: lc_fixWrkPlCd.getValue()
                    ,wrkPlNm: lc_fixWrkPlCd.getText(true)
                    ,inDt: ica_inDt.getValue()
                    ,inClsCd: lc_inClsCd.getValue()
                    ,inClsNm: lc_inClsCd.getText(true)
                    ,clntCd: ed_clntCdCond.getValue()
                    ,clntNm: ed_clntNmCond.getValue()
                    ,inToDt: ica_inDt.getValue()
                    ,apprvStsCd: lc_apprvStsCd.getValue()
        },
        viewerParam : {
            useprogressbar : false, // н”„лЎңк·ёл ҲмҠӨл°” м“ём§Җ л§җм§Җ
            printcommand : true,
            zoom : 90, // л°°мңЁ м„Өм •
        },
        formParam: {

        }
    };
    scwin.openPopup(data);
};

scwin.openPopup = async function(data){
    let opts = {
        id: "ozReportPopup",
        popupName: "мҳӨмҰҲ лҰ¬нҸ¬нҠё",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "мҳӨмҰҲ лҰ¬нҸ¬нҠё"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};

//-------------------------------------------------------------------------
// м—‘м…Җ м¶ңл Ҙ
//-------------------------------------------------------------------------
scwin.f_Excel = async function () {
	// н•„мҲҳмһ…л Ҙн•ӯлӘ© мІҙнҒ¬	  
    let ret = await $c.gus.cfValidate([lc_homeClsCd, ica_inDt]);
    if (!ret) {
        return false;
    }

	var rowCnt = ds_eq420.getRowCount();
	if ( rowCnt > 0 ) {

        let sheetTitle = "мқјлі„кұ°лһҳмІҳлі„мһ…кі нҳ„нҷ©";
        const options = {
            fileName: sheetTitle + ".xlsx",
            sheetName: sheetTitle
        };
        $c.data.downloadGridViewExcel(gr_eq420, options);

	} else {
		// cfAlertMsg(MSG_CM_WRN_018,['[мӣ” м—…мІҙлі„ м •л№„мһҗмһ¬ мһ…кі нҳ„нҷ©] мһҗлЈҢ','[мЎ°нҡҢ]']);
        $c.win.alert($c.data.getMessage(MSG_CM_WRN_018, "[мқјлі„кұ°лһҳмІҳлі„мһ…кі нҳ„нҷ©] мһҗлЈҢ","[мЎ°нҡҢ]"));
	}    
}

//-------------------------------------------------------------------------
// м „мһҗкІ°мһ¬лҘј мң„н•ң лІ”м№ҷкёҲ лҰ¬мҠӨнҠё м •ліҙмҷҖ кұҙмҲҳ, мҙқкёҲм•Ўмқ„ лҰ¬н„ҙн•ңлӢӨ
//-------------------------------------------------------------------------
scwin.f_getFineItemList = function() {
    // лҰ¬мҠӨнҠём •ліҙ, кұҙмҲҳ к·ёлҰ¬кі  мҙқкёҲм•Ў мҶҚм„ұмқ„ к°Җм§ҖлҠ” мҳӨлёҢм қнҠё
    // var oResult = new Object();
    var oResult = {};
    oResult.itemList = '';
    oResult.itemSize = 0;
    oResult.itemTotal = 0;
    for(var i=0; i<ds_eq420.getTotalRow(); i++) {
        var rowJson = ds_eq420.getRowJSON(i);
        if ( rowJson.chkYn == "1") {
            if( oResult.itemList == "" )
                oResult.itemList +=       rowJson.fixWrkPlCd + ":" + rowJson.buyNo + ":" + rowJson.buySeq;
            else
                oResult.itemList += "," + rowJson.fixWrkPlCd + ":" + rowJson.buyNo + ":" + rowJson.buySeq;

            oResult.itemSize += 1;
            oResult.itemTotal += ds_eq420.amt;
        }
    }
    return oResult;
};

//-------------------------------------------------------------------------
// м „мһҗкІ°мһ¬мҡ”мІӯ Tray Componentм—җм„ң EP мӮ¬мҡ©мһҗ IDк°Җм ёмҳӨкё°
//-------------------------------------------------------------------------	
scwin.f_getSSOInfo = function() {   
    var EXIST_YN = 0 ;
    var epUserId = "";

    try { 
        EXIST_YN = SSOCheck.IsExist("GROUP") ;
    } catch ( exception ) { 
        EXIST_YN = 0 ;
    }

    if(EXIST_YN==1) {  	
        SSO_LOGIN_YN = true ;	     
        epUserId = SSOCheck.GetUID("GROUP");	// EPмӮ¬мҡ©мһҗID	      
    }    	

    return epUserId;
};

//-------------------------------------------------------------------------
// м „мһҗкІ°мһ¬мҡ”мІӯ
//-------------------------------------------------------------------------
scwin.f_RequestElectronicApprove = async function() {

try{
    let vReqApprvDocKndCd = "015"					// кІ°мһ¬л¬ём„ңмў…лҘҳ -- м •л№„л¶Җн’Ҳмһ…кі лӮҙм—ӯ
    let vReqUserId = scwin.userId; 	// кІ°мһ¬мҡ”мІӯмһҗ ID
    let vEpUsrId = scwin.vepId;//f_getSSOInfo();  				// EPмӮ¬мҡ©мһҗ ID
    let today = ica_inDt.getValue();
    let homeClsCd  = "";
    let fixWrkPlCd = "";
    homeClsCd  = (lc_homeClsCd.getText()).split(":")[1];
    fixWrkPlCd = lc_fixWrkPlCd.getText();
    if ( fixWrkPlCd != "м „мІҙ" ) {
        homeClsCd = "-" + homeClsCd + "(" + lc_fixWrkPlCd.getText(true) + ")"
    }

    let vReqApprvTitle = "м •л№„л¶Җн’Ҳмһ…кі лӮҙм—ӯ-" + homeClsCd + "["  + today.substring(0,4) + "л…„ " 
                                                            + today.substring(4,6) + "мӣ” " 
                                                            + today.substring(6,8) + "мқј]" ;	//кІ°мһ¬м ңлӘ© 
    let fineInfo = await scwin.f_getFineItemList();

    if( fineInfo.itemSize == 0 ){
        await $c.gus.cfAlertMsg("м „мһҗкІ°мһ¬ лҢҖмғҒмқ„ м„ нғқн•ҙмЈјмӢӯмӢңмҳӨ.");
        return false;
    }

    if( vEpUsrId=="" ){
        //$c.gus.cfAlertMsg(" EPмӮ¬мҡ©мһҗ IDм •ліҙк°Җ м—ҶмҠөлӢҲлӢӨ.");
        //return false;
    }

    let rtn = await $c.win.confirm("м „мһҗкІ°мһ¬ мҡ”мІӯн•ҳмӢңкІ мҠөлӢҲк№Ң?");
	if(!rtn) {
		return;
	}

    let cnt =0;
    let amtSum = 0;
    let vatSum = 0;	
    let partNm = "";
    let partCd = "";

    // кІ°мһ¬мғҒм„ём •ліҙ
    let vApprvDtlInfo  = '<p><font face=көҙлҰј>1. м •л№„л¶Җн’Ҳмһ…кі лӮҙм—ӯ</font></p>';
    vApprvDtlInfo += '<table width=950 border=1>';
    vApprvDtlInfo += '<tr>';
    vApprvDtlInfo += '<td width=60  align=center><font size=2 face=көҙлҰј>мһ‘м—…мһҘ</font></td>';
    vApprvDtlInfo += '<td width=130 align=center><font size=2 face=көҙлҰј>кұ°лһҳмІҳ</font></td>';
    vApprvDtlInfo += '<td width=70  align=center><font size=2 face=көҙлҰј>кІҖмҲҳлІҲнҳё</font></td>';
    vApprvDtlInfo += '<td width=120 align=center><font size=2 face=көҙлҰј>л¶Җн’ҲмҪ”л“ң</font></td>';		
    vApprvDtlInfo += '<td width=150 align=center><font size=2 face=көҙлҰј>л¶Җн’ҲлӘ…</font></td>';
    vApprvDtlInfo += '<td width=100 align=center><font size=2 face=көҙлҰј>мһҘл№„лӘЁлҚё</font></td>';
    vApprvDtlInfo += '<td width=30 align=right><font size=2 face=көҙлҰј>мҲҳлҹү</font></td>';
    vApprvDtlInfo += '<td width=70 align=right><font size=2 face=көҙлҰј>лӢЁк°Җ</font></td>';
    vApprvDtlInfo += '<td width=80 align=right><font size=2 face=көҙлҰј>кёҲм•Ў</font></td>';
    vApprvDtlInfo += '<td width=80 align=right><font size=2 face=көҙлҰј>л¶Җк°Җм„ё</font></td>';
    vApprvDtlInfo += '</tr>';

    for(let k=0; k<ds_eq420.getRowCount() ; k++){
        // if( ds_eq420.getCellData(k, "chkYn") == "1" && ds_eq420.RowLevel(k) == 0 ) {
        if( ds_eq420.getCellData(k, "chkYn") == "1" ) {

            partNm = ds_eq420.getCellData(k, "partNm");
            partNm = partNm.replace("'", "");
            partNm = partNm.replace('"', "");
            partCd = ds_eq420.getCellData(k, "partCd")
            partCd = partCd.replace("'", "");
            partCd = partCd.replace('"', "");				
            vApprvDtlInfo += '<tr>';
            vApprvDtlInfo += '<td align=center><font size=2 face=көҙлҰј>' + ds_eq420.getCellData(k, "fixWrkPlNm") + '</font></td>';
            vApprvDtlInfo += '<td align=left><font size=2 face=көҙлҰј>' + ds_eq420.getCellData(k, "clntNm")+ '</font></td>';	
            vApprvDtlInfo += '<td align=center><font size=2 face=көҙлҰј>' + ds_eq420.getCellData(k, "buyNo")+ '</font></td>';	
            vApprvDtlInfo += '<td align=center><font size=2 face=көҙлҰј>' + partCd + '</font></td>';	
            vApprvDtlInfo += '<td align=left><font size=2 face=көҙлҰј>' + partNm + '</font></td>';	
            vApprvDtlInfo += '<td align=left><font size=2 face=көҙлҰј>' + ds_eq420.getCellData(k, "eqModelNm")+ '</font></td>';	
            vApprvDtlInfo += '<td align=right><font size=2 face=көҙлҰј>' + $c.gus.cfInsertComma(ds_eq420.getCellData(k, "qty")) + '</font></td>';	
            vApprvDtlInfo += '<td align=right><font size=2 face=көҙлҰј>' + $c.gus.cfInsertComma(ds_eq420.getCellData(k, "upr")) + '</font></td>';
            vApprvDtlInfo += '<td align=right><font size=2 face=көҙлҰј>' + $c.gus.cfInsertComma(ds_eq420.getCellData(k, "amt")) + '</font></td>';
            vApprvDtlInfo += '<td align=right><font size=2 face=көҙлҰј>' + $c.gus.cfInsertComma(ds_eq420.getCellData(k, "vat")) + '</font></td>';
            vApprvDtlInfo += '</tr>';

            cnt = cnt + 1;
            amtSum = amtSum + parseFloat(ds_eq420.getCellData(k, "amt"));
            vatSum = vatSum + parseFloat(ds_eq420.getCellData(k, "vat"))
        }
    }

    vApprvDtlInfo += '<tr>';
    vApprvDtlInfo += '<td align=center><font size=2 face=көҙлҰј>&nbsp;</font></td>';
    vApprvDtlInfo += '<td align=center><font bold size=2 face=көҙлҰј>' + 'н•©кі„' + '</font></td>';	
    vApprvDtlInfo += '<td align=center><font size=2 face=көҙлҰј>&nbsp;</font></td>';	
    vApprvDtlInfo += '<td align=center><font bold size=2 face=көҙлҰј>' + cnt +  ' кұҙ</font></td>';	
    vApprvDtlInfo += '<td align=left><font size=2 face=көҙлҰј>&nbsp;</font></td>';	
    vApprvDtlInfo += '<td align=left><font size=2 face=көҙлҰј>&nbsp;</font></td>';	
    vApprvDtlInfo += '<td align=right><font size=2 face=көҙлҰј>&nbsp;</font></td>';	
    vApprvDtlInfo += '<td align=right><font size=2 face=көҙлҰј>&nbsp;</font></td>';
    vApprvDtlInfo += '<td align=right><font bold size=2 face=көҙлҰј>' + $c.gus.cfInsertComma(amtSum) + '</font></td>';
    vApprvDtlInfo += '<td align=right><font bold size=2 face=көҙлҰј>' + $c.gus.cfInsertComma(vatSum) + '</font></td>';
    vApprvDtlInfo += '</tr>';
    vApprvDtlInfo += '</table>';

    const params = {
        apprvDocKndCd      : vReqApprvDocKndCd , //кІ°мһ¬л¬ём„ңмў…лҘҳ
        reqUserId : vReqUserId ,//кІ°мһ¬мҡ”мІӯмһҗ
        epUserId : vEpUsrId ,//EPмӮ¬мҡ©мһҗ
        apprvTitle : vReqApprvTitle ,//кІ°мһ¬м ңлӘ©
        apprvDtlInfo : vApprvDtlInfo ,//кІ°мһ¬л¬ём„ңм–‘мӢқ
        partsList : fineInfo.itemList ,
        bmodifylines : "Y" , // л¬ём„ңм •ліҙ ліҖкІҪ к°ҖлҠҘ м—¬л¶Җ
        bmodifybody : "Y" , // л¬ём„ң ліёл¬ё мҲҳм • м—¬л¶Җ
        bmodifyattach : "Y" , // мІЁл¶ҖнҢҢмқј кё°лҠҘ нҷңм„ұнҷ” м—¬л¶Җ
    };
    //лҚ°мқҙн„°м…Ӣм—җ м •ліҙм„Өм •
    dma_frmReqApprove.setJSON(params);

    let url = "/ps.eq.adjmmgnt.RequestEquipmentPartsBuyApproveCMD.do";
    let targetName = "aprvPopup"; // кі м • мқҙлҰ„(мһ¬мӮ¬мҡ©)

    let data = dma_frmReqApprove.getJSON() || {};

    const form = document.createElement("form");
    form.method = "POST";
    form.action = url;
    form.target = targetName;

    // нҢқм—… м°ЁлӢЁ нҡҢн”ј: мӮ¬мҡ©мһҗ нҒҙлҰӯ мқҙлІӨнҠё м•Ҳм—җм„ң мӢӨн–үлҗҳм–ҙм•ј н•Ё
    const win = window.open("", targetName); // about:blank лҢҖмӢ  л№Ҳ л¬ёмһҗм—ҙлЎң мһ¬мӮ¬мҡ©
    // нҢқм—…мқҙ л§үнһҲл©ҙ winмқҙ nullмқј мҲҳ мһҲмқҢ
    if (!win) {
    // м—¬кё°м„ң к·ёлғҘ location мқҙлҸҷн•ҳкұ°лӮҳ alert мІҳлҰ¬ л“ұ
    console.warn("Popup blocked");
    }

    Object.keys(data).forEach((key) => {
        const input = document.createElement("input");
        input.type = "hidden";
        input.name = key;
        input.value = (data[key] ?? "").toString();
        form.appendChild(input);
    });

    document.body.appendChild(form);
    console.log("POST keys:", Object.keys(data));
    console.log("epUserId:", data.epUserId);
    console.log("apprvDtlInfo length:", (data.apprvDtlInfo || "").length);
    console.log("apprvTitle:", data.apprvTitle);
    form.submit();
    document.body.removeChild(form);

}catch (e){
    console.log("f_aprv : " + e);
}

};

